using UnityEngine;
using Climbing;

public class FixPlayerPhysics
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "Player not found.";

        GameObject pm = cc.gameObject;
        Animator anim = pm.GetComponent<Animator>();
        Rigidbody rb = pm.GetComponent<Rigidbody>();

        string report = $"--- Fixing Player: {pm.name} ---\n";

        if (anim != null) {
            report += $"Animator.applyRootMotion was {anim.applyRootMotion}. Setting it to FALSE.\n";
            anim.applyRootMotion = false;
        }

        if (rb != null) {
            rb.useGravity = true;
            rb.isKinematic = false;
            report += "Ensured Gravity is ON and Kinematic is OFF.\n";
        }

        return report;
    }
}
